var EZ_TRANSLATIONS = {"en": {"nav_home": "Home", "nav_services": "Services", "nav_meet": "Meet Ez", "nav_contact": "Contact", "nav_haircare": "Hair Care", "nav_gallery": "Gallery", "nav_book": "Book Now", "index_marquee": ["Private", "Bilingual", "Intentional", "Raleigh, NC", "Luxury Extensions", "Custom Color", "By Appointment"], "index_hero_eyebrow": "Private Studio · Raleigh, NC", "index_hero_h1": "Where Hair Meets", "index_hero_em": "INTENTION", "index_hero_body": "A private experience built around your hair, not a template. Serving clients in English and Spanish, every appointment is curated to how you live, your texture, and your goals.", "index_hero_btn1": "Reserve a Session", "index_hero_btn2": "View Services", "index_scroll": "Scroll", "index_p1_title": "Private", "index_p1_body": "A one-on-one experience in a quiet, focused space. No distractions. Just you, your hair, and undivided attention.", "index_p2_title": "Intentional", "index_p2_body": "Every technique, product, and decision is made with purpose. For results that last and hair that feels as good as it looks.", "index_p3_title": "Yours", "index_p3_body": "No templates, no shortcuts. Every appointment is shaped around your texture, your lifestyle, and what you actually want.", "index_svc_eyebrow": "What I Offer", "index_svc_h1": "Curated Services,", "index_svc_em": "Crafted for You", "index_c1_label": "Service", "index_c1_title": "Effortless Color", "index_c1_desc": "Soft balayage and foilayage creating dimensional, lived-in color that's easy to maintain.", "index_c1_ap1": "Soft balayage and foilayage designed to create dimensional, lived-in color that grows out beautifully. Perfect for natural-looking results without constant upkeep.", "index_c1_ap2": "Every color appointment begins with a consultation to understand your hair history, lifestyle, and goals. No two results are the same.", "index_c1_abtn": "Book Now", "index_c2_label": "Service", "index_c2_title": "Cuts + Styling", "index_c2_desc": "Personalized to fit how you actually live in your hair: your texture, your routine, your lifestyle.", "index_c2_ap1": "Every cut is shaped around how you actually live in your hair, your routine, your texture, your style. Not a formula, not a template. A cut that works for your real life.", "index_c2_ap2": "Includes a blowout and style finish so you leave looking and feeling your best.", "index_c2_abtn": "Book Now", "index_c3_label": "Service", "index_c3_title": "Extension Services", "index_c3_desc": "Custom extensions tailored to your texture, lifestyle, and goals. Length, volume, or both. Done to look completely natural.", "index_c3_ap1": "Custom extensions tailored to your hair texture, density, lifestyle, and goals. I'll go over every method available, maintenance expectations, and pricing during your consultation — no surprises.", "index_c3_ap2": "Whether you want added length, volume, or both, the result will look and feel completely natural.", "index_c3_abtn": "Book a Consultation", "index_learn_more": "Learn More", "index_view_all": "View All Services", "index_testi_eyebrow": "Client Love", "index_testi_h1": "What My Clients", "index_testi_em": "Are Saying", "index_t1": "I have never felt so seen in a salon. Ezequiel listened to exactly what I wanted and delivered hair I am obsessed with. I won't go anywhere else.", "index_t1_author": "Maria L.", "index_t2": "The private setting made all the difference. It was relaxing, personal, and my color came out absolutely stunning. Worth every penny.", "index_t2_author": "Ashley R.", "index_t3": "Being able to speak in Spanish during my appointment made the whole experience so comfortable. Exceptional work and exceptional care.", "index_t3_author": "Carmen V.", "index_about_eyebrow": "Meet the Artist", "index_about_h1": "Hair is more than", "index_about_em": "a service.", "index_about_body": "With experience in color, extensions, and precision cutting, I bring both technical mastery and a deeply personal touch to every appointment. Serving clients in English and Spanish, my private studio was built on the belief that luxury should feel accessible, intentional, and uniquely yours.", "index_about_btn": "Full Story", "index_cta_eyebrow": "Ready When You Are", "index_cta_h1": "Ready to create something", "index_cta_em": "beautiful?", "index_cta_body": "New to EzHairr? Start with a consultation so I can review your hair history, goals, and build a plan together.", "index_cta_btn1": "Book an Appointment", "index_cta_btn2": "New Client? Request a Consultation", "footer_navigate": "Navigate", "footer_contact": "Get in Touch", "footer_copy": "© 2026 EzHairr. All rights reserved.", "footer_location": "Raleigh, North Carolina", "svc_marquee": ["Color", "Extensions", "Cuts", "Styling", "Balayage", "Foilayage", "Blowouts", "Consultations"], "svc_eyebrow": "What I Offer", "svc_h1": "The Service", "svc_em": "Menu", "svc_body": "Every service is a conversation. New clients are always welcome to start with a consultation.", "svc_first_title": "First Time?", "svc_first_sub": "Start with a Consultation", "svc_first_body": "Not sure which service is right for you? A consultation is always the best first step. I'll review your hair history, goals, and build a plan that actually fits your life.", "svc_first_btn": "Request a Consultation", "svc1_em": "Haircutting", "svc1_body": "Every cut is personalized to fit how you actually live in your hair. Your routine, your style, your texture — a cut that works in real life.", "svc2_h1": "Effortless", "svc2_em": "Color", "svc2_body": "Soft balayage and foilayage creating dimensional, lived-in color that's easy to maintain. Perfect for natural-looking results without constant upkeep.", "svc3_h1": "Classic", "svc3_em": "Color", "svc3_body": "From root touch-ups and solid all-over color to gloss refreshes and full color transformations. Tailored to your hair and your goals.", "svc4_h1": "Extension", "svc4_em": "Services", "svc4_body": "During your consultation, I'll go over everything you need to know about extensions, including method, maintenance, and pricing — no surprises.", "svc5_h1": "Classic", "svc5_em": "Blowout", "svc5_body": "A polished, smooth finish that lasts. Whether you want sleek, voluminous, or something in between, the blowout is tailored to your hair type and style.", "svc_book": "Book Now", "svc_cta_eyebrow": "Ready to Begin?", "svc_cta_h1": "Book your", "svc_cta_em": "experience", "svc_cta_body": "New clients always start with a consultation. It's where the magic begins.", "svc_cta_btn": "Request a Consultation", "about_marquee": ["Private", "Bilingual", "Intentional", "Raleigh, NC", "Luxury Hair Studio", "By Appointment Only"], "about_eyebrow": "The Artist", "about_h1": "Meet", "about_em": "Ezequiel", "about_hero_body": "Hair is more than a service. It's a relationship built on trust, vision, and intention.", "about_bg_eyebrow": "Background", "about_bg_h2": "Craft. ", "about_bg_em": "Connection.", "about_bg_h2b": " Color.", "about_p1": "I founded EzHairr on a simple but powerful idea: that the salon experience should feel as good as the results. As a bilingual stylist serving Raleigh's diverse community, I built a private studio where every client feels genuinely seen, heard, and cared for.", "about_p2": "Every appointment is built around you. Your texture, your lifestyle, your vision. That's the only way I know how to work.", "about_p3": "Whether you're coming in for a full color transformation or a simple trim, you'll leave feeling confident, heard, and genuinely taken care of.", "about_v1_title": "Bilingual Service", "about_v1_body": "Fluent in English and Spanish, serving Raleigh's full community with warmth and ease.", "about_v2_title": "Private Studio", "about_v2_body": "A focused, one-on-one environment. No crowds, no distractions, just your appointment.", "about_v3_title": "Intentional Results", "about_v3_body": "Every decision is made with purpose, from the products used to the final style.", "about_cta_eyebrow": "Ready to Begin?", "about_cta_h1": "Book your", "about_cta_em": "experience", "about_cta_body": "New clients always start with a consultation. It's where the magic begins.", "about_cta_btn": "Request a Consultation", "contact_marquee": ["Book Now", "Say Hello", "Raleigh, NC", "(919) 444-2266", "hello@ezhairr.com", "By Appointment"], "contact_eyebrow": "Get in Touch", "contact_h1": "Let's", "contact_em": "Connect", "contact_hero_body": "Have a question? Want to book? Find all of Ezequiel's contact info below. New clients can use the form to request a consultation.", "contact_info_eyebrow": "Studio Info", "contact_info_h2": "Find", "contact_info_em": "Me", "contact_loc": "Location", "contact_phone": "Phone / Text", "contact_email_lbl": "Email", "contact_hours": "Hours", "contact_hours_v1": "By appointment only.", "contact_hours_v2": "New clients start with a consultation.", "contact_lang": "Languages", "contact_lang_v": "English & Spanish", "contact_book_btn": "Book an Appointment", "contact_form_eyebrow": "New Clients", "contact_form_h2": "Request a", "contact_form_em": "Consultation", "contact_form_note": "New to EzHairr? All new clients begin with a consultation. Fill out the form below and include a photo of your natural hair. Ezequiel will reach out within 24 hours.", "contact_existing": "Already a client?", "contact_existing_link": "Book your appointment directly here.", "contact_fname": "First Name", "contact_lname": "Last Name", "contact_email": "Email Address", "contact_phone_opt": "Phone (optional)", "contact_service": "Service Interest", "contact_service_default": "Select a service", "contact_msg": "Message", "contact_photo": "Photo of Your Natural Hair (optional)", "contact_photo_hint": "First-time clients are encouraged to share a photo of their natural hair so Ezequiel can prepare for your consultation.", "contact_submit": "Send Message", "contact_success_h": "Message Received", "contact_success_p": "Thanks for reaching out. I'll be in touch shortly.", "contact_cta_eyebrow": "Ready to Begin?", "contact_cta_h1": "Book your", "contact_cta_em": "experience", "contact_cta_body": "New clients always start with a consultation. It's where the magic begins.", "contact_cta_btn": "Request an Appointment", "text_me": "Text Me", "hc_eyebrow": "Education", "hc_h1": "Hair", "hc_em": "Care Guide", "hc_hero_body": "Your hair deserves to be taken care of between appointments. This guide covers everything from daily routines to aftercare, so your results last longer and your hair stays healthy.", "hc_nav_wash": "Washing", "hc_nav_prod": "Products", "hc_nav_after": "Aftercare", "hc_nav_prep": "Appointment Prep", "hc_marquee": ["Washing", "Products", "Aftercare", "Extensions", "Color", "Blowouts", "Appointment Prep"], "hc_wash_eyebrow": "Daily Routine", "hc_wash_h2": "How Often to", "hc_wash_em": "Wash Your Hair", "hc_wash_body": "There is no universal answer. How often you wash depends on your hair type, scalp, and lifestyle. Over-washing strips natural oils; under-washing leads to buildup.", "hc_prod_eyebrow": "What to Use", "hc_prod_h2": "Choosing the Right", "hc_prod_em": "Products", "hc_prod_body": "The right products make a significant difference in how your hair looks and feels between appointments.", "hc_after_eyebrow": "After Your Appointment", "hc_after_h2": "Aftercare by", "hc_after_em": "Service", "hc_after_body": "How you treat your hair in the 48 to 72 hours after your appointment matters. Follow these guidelines to protect your results.", "hc_prep_eyebrow": "Before You Come In", "hc_prep_h2": "How to Prepare for", "hc_prep_em": "Your Appointment", "hc_prep_body": "Coming in prepared helps make the most of your time in the chair and ensures the best possible results.", "hc_cta_eyebrow": "Ready to Come In?", "hc_cta_h2": "Let's build a plan", "hc_cta_em": "for your hair", "hc_cta_body": "New clients start with a consultation. Existing clients can book directly online.", "hc_cta_btn": "Request a Consultation", "gl_eyebrow": "The Work", "gl_h1": "Client", "gl_em": "Gallery", "gl_hero_body": "A look at real results from real clients. Every transformation is unique, intentional, and built around the individual.", "gl_marquee": ["Color", "Extensions", "Balayage", "Cuts", "Blowouts", "Transformations", "Raleigh, NC"], "gl_cta_eyebrow": "Ready for Your Transformation?", "gl_cta_h2": "Let's create something", "gl_cta_em": "beautiful", "gl_cta_body": "New clients start with a consultation. Existing clients can book directly.", "gl_cta_btn1": "Request a Consultation", "gl_cta_btn2": "Book an Appointment", "hc_wash_fine_label": "Fine or Oily Hair", "hc_wash_fine_title": "Every 1 to 2 Days", "hc_wash_fine_body": "Fine hair tends to get weighed down quickly by oil and product. Washing more frequently helps maintain volume and a clean scalp. Use a lightweight, volumizing shampoo and avoid heavy conditioners at the root.", "hc_wash_med_label": "Normal or Medium Hair", "hc_wash_med_title": "Every 2 to 3 Days", "hc_wash_med_body": "Normal hair can handle a longer stretch between washes. A good dry shampoo on day two or three can extend freshness. Focus conditioner on the mid-lengths and ends, not the scalp.", "hc_wash_thick_label": "Thick, Curly, or Dry Hair", "hc_wash_thick_title": "Every 3 to 7 Days", "hc_wash_thick_body": "Thicker and curlier hair types retain moisture better and can go longer between washes. Frequent washing can cause dryness and frizz. Focus on deep conditioning and sealing in moisture with oil or cream.", "hc_wash_tip": "Pro tip:", "hc_wash_tip_body": "If your scalp is itchy or flaky, it may be a sign of buildup rather than dryness. Try a clarifying shampoo once a month to reset your scalp.", "hc_prod_intro": "The right products make a significant difference in how your hair looks and feels between appointments. Here is what to look for based on your hair type and service.", "hc_prod_color_label": "Color-Treated Hair", "hc_prod_color_title": "Color-Safe and Sulfate-Free", "hc_prod_color_body": "Color fades faster when exposed to harsh sulfates. Use a sulfate-free shampoo specifically formulated for color-treated hair.", "hc_prod_color_l1": "Look for: color-safe, sulfate-free, UV protection", "hc_prod_color_l2": "Avoid: clarifying shampoos (use sparingly), hot water", "hc_prod_color_l3": "Add: weekly color-depositing or toning conditioner for blondes", "hc_prod_ext_label": "Extensions", "hc_prod_ext_title": "Lightweight and Residue-Free", "hc_prod_ext_body": "Product buildup at the bonds or wefts can cause slippage and damage. Keep it clean and light near the roots.", "hc_prod_ext_l1": "Look for: sulfate-free, extension-safe, moisturizing", "hc_prod_ext_l2": "Avoid: oils or serums near the bonds or attachment points", "hc_prod_ext_l3": "Add: a detangling spray for daily brushing", "hc_prod_dry_label": "Dry or Damaged Hair", "hc_prod_dry_title": "Moisture and Protein Balance", "hc_prod_dry_body": "Dry hair needs hydration, but too much protein can make it brittle. Alternate between moisturizing and protein treatments.", "hc_prod_dry_l1": "Look for: argan oil, keratin, shea butter, hyaluronic acid", "hc_prod_dry_l2": "Avoid: alcohol-based products, excessive heat without protection", "hc_prod_dry_l3": "Add: weekly deep conditioning mask", "hc_prod_tip": "General rule:", "hc_prod_tip_body": "Less is more. Too many products layered together can cause buildup that weighs hair down and dulls color. Start with a shampoo, conditioner, and one styling product and add from there.", "hc_after_intro": "How you treat your hair in the 48 to 72 hours after your appointment matters. Follow these guidelines to protect your results and make them last.", "hc_color_label": "After a Color Service", "hc_color_title": "Protect and Preserve", "hc_color_s1_h": "Wait 48 to 72 hours before washing", "hc_color_s1_b": "Freshly colored hair needs time for the cuticle to close and the pigment to fully set. Washing too soon causes premature fading.", "hc_color_s2_h": "Use cool or lukewarm water", "hc_color_s2_b": "Hot water opens the hair cuticle and accelerates color fade. Cool water seals the cuticle and preserves vibrancy.", "hc_color_s3_h": "Switch to a color-safe shampoo", "hc_color_s3_b": "Use a sulfate-free, color-safe formula from your very first wash after the service and going forward.", "hc_color_s4_h": "Avoid chlorine and saltwater", "hc_color_s4_b": "Both strip color quickly. If you swim, wear a cap or rinse your hair with clean water immediately after.", "hc_blowout_label": "After a Blowout", "hc_blowout_title": "Extend the Life of Your Style", "hc_blowout_s1_h": "Avoid moisture for 24 hours", "hc_blowout_s1_b": "Steam, sweat, and humidity are the enemies of a fresh blowout. Try to stay dry for at least the first day.", "hc_blowout_s2_h": "Sleep on a silk pillowcase", "hc_blowout_s2_b": "Silk reduces friction and helps your style hold its shape overnight. A loose braid or top knot also helps preserve the blowout.", "hc_blowout_s3_h": "Use dry shampoo strategically", "hc_blowout_s3_b": "Apply dry shampoo at the roots on day two or three to refresh volume without washing. Let it sit for a few minutes before brushing through.", "hc_blowout_s4_h": "Touch up with low heat", "hc_blowout_s4_b": "On day two, a round brush with a low-heat dryer or a flat iron on a lower setting can revive the style without damage.", "hc_ext_label": "After Extension Services", "hc_ext_title": "Care for Your Investment", "hc_ext_s1_h": "Brush gently twice daily", "hc_ext_s1_b": "Use a soft-bristle or loop brush starting from the ends and working up. Never brush from the root down as this puts tension on the bonds.", "hc_ext_s2_h": "Wash with care", "hc_ext_s2_b": "Wash in a downward motion, never circular. Circular washing can tangle extensions and weaken bonds over time.", "hc_ext_s3_h": "Dry thoroughly before bed", "hc_ext_s3_b": "Going to sleep with wet extensions can cause matting and weaken the attachment. Always dry completely before lying down.", "hc_ext_s4_h": "Braid loosely at night", "hc_ext_s4_b": "A loose braid or ponytail prevents tangling while you sleep and reduces stress on the bonds.", "hc_cut_label": "After a Haircut", "hc_cut_title": "Keep Your Shape Fresh", "hc_cut_s1_h": "Schedule your next trim", "hc_cut_s1_b": "Most cuts benefit from a trim every 6 to 12 weeks depending on hair growth and style. Regular trims prevent split ends from traveling up the shaft.", "hc_cut_s2_h": "Use the right styling products", "hc_cut_s2_b": "Match your products to your texture. Fine hair needs lightweight hold; thick hair benefits from smoothing creams or oils.", "hc_cut_s3_h": "Protect from heat", "hc_cut_s3_b": "Always apply a heat protectant before blow-drying or using hot tools. This prevents breakage and keeps ends healthy between appointments.", "hc_cut_s4_h": "Trim split ends promptly", "hc_cut_s4_b": "Split ends travel upward if left untreated. Even a small trim every few weeks keeps the style looking intentional and clean.", "hc_prep_intro": "Coming in prepared helps make the most of your time in the chair and ensures the best possible results. Here is how to prepare depending on your service.", "hc_prep_color_label": "For a Color Service", "hc_prep_color_title": "Come in with Clean, Dry Hair", "hc_prep_color_body": "Wash your hair 24 to 48 hours before your color appointment. Slightly dirty hair is actually ideal as natural oils protect the scalp during the coloring process.", "hc_prep_color_l1": "Avoid heavy styling products or oils the day of", "hc_prep_color_l2": "Bring reference photos of colors you love", "hc_prep_color_l3": "Wear a top you do not mind getting color on", "hc_prep_color_l4": "Be ready to discuss your hair history honestly", "hc_prep_ext_label": "For Extension Services", "hc_prep_ext_title": "Clean and Product-Free", "hc_prep_ext_body": "Extensions adhere and blend best when your hair is freshly washed and completely free of product buildup.", "hc_prep_ext_l1": "Wash hair the morning of or night before", "hc_prep_ext_l2": "Do not apply any oils, serums, or dry shampoo", "hc_prep_ext_l3": "Come in with hair down and detangled", "hc_prep_ext_l4": "Bring photos of your length and volume goals", "hc_prep_cut_label": "For a Haircut or Blowout", "hc_prep_cut_title": "Come in Comfortable", "hc_prep_cut_body": "For a cut, come in with your hair in its natural state so the cut can be tailored to how your hair actually behaves. For a blowout, come with clean or lightly washed hair.", "hc_prep_cut_l1": "Avoid heavy products the morning of", "hc_prep_cut_l2": "Bring photos of styles you like", "hc_prep_cut_l3": "Let the stylist know your daily routine", "hc_prep_cut_l4": "Be specific about how much length you want to keep", "hc_prep_tip": "First-time client?", "hc_prep_tip_body": "Use the consultation request form to share a photo of your natural hair before your appointment. This helps Ezequiel come prepared with a plan tailored specifically to you.", "hc_prep_tip_link": "Request a consultation here."}, "es": {"nav_home": "Inicio", "nav_services": "Servicios", "nav_meet": "Conoce a Ez", "nav_contact": "Contacto", "nav_haircare": "Cuidado del Cabello", "nav_gallery": "Galería", "nav_book": "Reservar", "index_marquee": ["Privado", "Bilingüe", "Intencional", "Raleigh, NC", "Extensiones de Lujo", "Color Personalizado", "Solo con Cita"], "index_hero_eyebrow": "Estudio Privado · Raleigh, NC", "index_hero_h1": "Donde el Cabello Encuentra", "index_hero_em": "INTENCIÓN", "index_hero_body": "Una experiencia privada construida alrededor de tu cabello. Atendiendo clientas en español e inglés, cada cita es personalizada según tu estilo de vida, tu textura y tus metas.", "index_hero_btn1": "Reservar una Sesión", "index_hero_btn2": "Ver Servicios", "index_scroll": "Deslizar", "index_p1_title": "Privado", "index_p1_body": "Una experiencia uno a uno en un espacio tranquilo y enfocado. Sin distracciones. Solo tú, tu cabello y atención exclusiva.", "index_p2_title": "Intencional", "index_p2_body": "Cada técnica, producto y decisión se toma con propósito. Para resultados duraderos y un cabello que se siente tan bien como se ve.", "index_p3_title": "Tuyo", "index_p3_body": "Sin plantillas ni atajos. Cada cita se adapta a tu textura, tu estilo de vida y lo que realmente quieres.", "index_svc_eyebrow": "Lo Que Ofrezco", "index_svc_h1": "Servicios con Cuidado,", "index_svc_em": "Creados para Ti", "index_c1_label": "Servicio", "index_c1_title": "Color Sin Esfuerzo", "index_c1_desc": "Balayage y foilayage suave que crea un color dimensional y natural, fácil de mantener.", "index_c1_ap1": "Balayage y foilayage suave diseñado para crear un color dimensional que crece hermosamente. Perfecto para clientas que quieren resultados naturales sin mucho mantenimiento.", "index_c1_ap2": "Cada cita de color comienza con una consulta para entender tu historial, estilo de vida y metas.", "index_c1_abtn": "Reservar", "index_c2_label": "Servicio", "index_c2_title": "Cortes y Peinado", "index_c2_desc": "Personalizado para adaptarse a cómo realmente vives con tu cabello: tu textura, tu rutina, tu estilo de vida.", "index_c2_ap1": "Cada corte se adapta a tu rutina, tu textura, tu estilo. No una fórmula. Un corte que funciona en tu vida real.", "index_c2_ap2": "Incluye blow-out y acabado de estilo para que salgas sintiéndote increíble.", "index_c2_abtn": "Reservar", "index_c3_label": "Servicio", "index_c3_title": "Extensiones", "index_c3_desc": "Extensiones personalizadas según tu textura, estilo de vida y metas. Largo, volumen o ambos. De forma completamente natural.", "index_c3_ap1": "Extensiones personalizadas según tu textura, densidad, estilo de vida y metas. Repasaré cada método, mantenimiento y precios en tu consulta, sin sorpresas.", "index_c3_ap2": "Ya sea más largo, volumen o ambos, el resultado se verá y sentirá completamente natural.", "index_c3_abtn": "Solicitar Consulta", "index_learn_more": "Ver Más", "index_view_all": "Ver Todos los Servicios", "index_testi_eyebrow": "Opiniones", "index_testi_h1": "Lo Que Dicen", "index_testi_em": "Mis Clientes", "index_t1": "Nunca me había sentido tan vista en un salón. Ezequiel escuchó exactamente lo que quería y logró el cabello con el que estoy obsesionada.", "index_t1_author": "Maria L.", "index_t2": "El ambiente privado marcó toda la diferencia. Fue relajante y mi color quedó absolutamente espectacular. Vale cada centavo.", "index_t2_author": "Ashley R.", "index_t3": "Poder hablar en español durante mi cita hizo que toda la experiencia fuera muy cómoda. Un trabajo y trato excepcionales.", "index_t3_author": "Carmen V.", "index_about_eyebrow": "Conoce al Artista", "index_about_h1": "El cabello es más que", "index_about_em": "un servicio.", "index_about_body": "Con experiencia en color, extensiones y corte de precisión, aporto tanto dominio técnico como un toque personal a cada cita. Atendiendo clientas en español e inglés, mi estudio privado se construyó sobre la creencia de que el lujo debe sentirse accesible, intencional y únicamente tuyo.", "index_about_btn": "Mi Historia", "index_cta_eyebrow": "Listo Cuando Tú lo Estés", "index_cta_h1": "¿Listo para crear algo", "index_cta_em": "hermoso?", "index_cta_body": "¿Nueva en EzHairr? Comienza con una consulta para revisar tu historial y construir un plan juntos.", "index_cta_btn1": "Reservar una Cita", "index_cta_btn2": "¿Nueva Clienta? Solicitar Consulta", "footer_navigate": "Navegar", "footer_contact": "Contáctanos", "footer_copy": "© 2026 EzHairr. Todos los derechos reservados.", "footer_location": "Raleigh, Carolina del Norte", "svc_marquee": ["Color", "Extensiones", "Cortes", "Peinado", "Balayage", "Foilayage", "Blow-out", "Consultas"], "svc_eyebrow": "Lo Que Ofrezco", "svc_h1": "Menú de", "svc_em": "Servicios", "svc_body": "Cada servicio es una conversación. Las nuevas clientas siempre pueden comenzar con una consulta.", "svc_first_title": "¿Primera vez?", "svc_first_sub": "Comienza con una Consulta", "svc_first_body": "¿No sabes qué servicio es el adecuado? Una consulta es siempre el mejor primer paso. Revisaré tu historial y construiré un plan que se adapte a tu vida.", "svc_first_btn": "Solicitar una Consulta", "svc1_em": "Corte de Cabello", "svc1_body": "Cada corte es personalizado para adaptarse a cómo realmente vives con tu cabello. Tu rutina, tu estilo, tu textura — un corte que funciona en la vida real.", "svc2_h1": "Color", "svc2_em": "Sin Esfuerzo", "svc2_body": "Balayage y foilayage suave que crea un color dimensional y natural, fácil de mantener.", "svc3_h1": "Color", "svc3_em": "Clásico", "svc3_body": "Desde retoques de raíz y color sólido hasta gloss y transformaciones completas. Adaptado a tu cabello y metas.", "svc4_h1": "Servicios de", "svc4_em": "Extensiones", "svc4_body": "Durante tu consulta, te explicaré todo sobre extensiones: método, mantenimiento y precios, sin sorpresas.", "svc5_h1": "Blow-out", "svc5_em": "Clásico", "svc5_body": "Un acabado pulido y suave que dura. Adaptado a tu tipo de cabello, ya sea liso, voluminoso o algo intermedio.", "svc_book": "Reservar", "svc_cta_eyebrow": "¿Listo para Comenzar?", "svc_cta_h1": "Reserva tu", "svc_cta_em": "experiencia", "svc_cta_body": "Las nuevas clientas siempre comienzan con una consulta. Ahí es donde comienza la magia.", "svc_cta_btn": "Solicitar una Consulta", "about_marquee": ["Privado", "Bilingüe", "Intencional", "Raleigh, NC", "Estudio de Lujo", "Solo con Cita"], "about_eyebrow": "El Artista", "about_h1": "Conoce a", "about_em": "Ezequiel", "about_hero_body": "El cabello es más que un servicio. Es una relación construida sobre confianza, visión e intención.", "about_bg_eyebrow": "Historia", "about_bg_h2": "Arte. ", "about_bg_em": "Conexión.", "about_bg_h2b": " Color.", "about_p1": "Fundé EzHairr sobre una idea simple pero poderosa: que la experiencia del salón debe sentirse tan bien como los resultados. Como estilista bilingüe en Raleigh, construí un estudio privado donde cada clienta se siente genuinamente vista, escuchada y cuidada.", "about_p2": "Cada cita está construida alrededor de ti. Tu textura, tu estilo de vida, tu visión. Es la única manera en que sé trabajar.", "about_p3": "Ya sea para una transformación completa de color o un simple corte, saldrás sintiéndote segura, escuchada y genuinamente cuidada.", "about_v1_title": "Servicio Bilingüe", "about_v1_body": "Fluido en inglés y español, sirviendo a la comunidad de Raleigh con calidez y facilidad.", "about_v2_title": "Estudio Privado", "about_v2_body": "Un ambiente enfocado, de uno a uno. Sin multitudes, sin distracciones, solo tu cita.", "about_v3_title": "Resultados Intencionales", "about_v3_body": "Cada decisión se toma con propósito, desde los productos hasta el estilo final.", "about_cta_eyebrow": "¿Listo para Comenzar?", "about_cta_h1": "Reserva tu", "about_cta_em": "experiencia", "about_cta_body": "Las nuevas clientas siempre comienzan con una consulta. Ahí es donde comienza la magia.", "about_cta_btn": "Solicitar una Consulta", "contact_marquee": ["Reservar", "Saludar", "Raleigh, NC", "(919) 444-2266", "hello@ezhairr.com", "Con Cita"], "contact_eyebrow": "Contáctanos", "contact_h1": "Hablemos", "contact_em": "", "contact_hero_body": "¿Tienes una pregunta? ¿Quieres reservar? Encuentra la información de contacto de Ezequiel abajo. Las nuevas clientas pueden usar el formulario para solicitar una consulta.", "contact_info_eyebrow": "Info del Estudio", "contact_info_h2": "Encuéntrame", "contact_info_em": "", "contact_loc": "Ubicación", "contact_phone": "Teléfono / Texto", "contact_email_lbl": "Correo", "contact_hours": "Horario", "contact_hours_v1": "Solo con cita previa.", "contact_hours_v2": "Las nuevas clientas comienzan con una consulta.", "contact_lang": "Idiomas", "contact_lang_v": "Inglés y Español", "contact_book_btn": "Reservar una Cita", "contact_form_eyebrow": "Nuevos Clientes", "contact_form_h2": "Solicitar una", "contact_form_em": "Consulta", "contact_form_note": "¿Nueva en EzHairr? Todas las nuevas clientas comienzan con una consulta. Completa el formulario e incluye una foto de tu cabello natural. Ezequiel se pondrá en contacto en 24 horas.", "contact_existing": "¿Ya eres clienta?", "contact_existing_link": "Reserva tu cita directamente aquí.", "contact_fname": "Nombre", "contact_lname": "Apellido", "contact_email": "Correo Electrónico", "contact_phone_opt": "Teléfono (opcional)", "contact_service": "Servicio de Interés", "contact_service_default": "Selecciona un servicio", "contact_msg": "Mensaje", "contact_photo": "Foto de tu Cabello Natural (opcional)", "contact_photo_hint": "Se recomienda a los nuevos clientes compartir una foto de su cabello natural para que Ezequiel pueda prepararse.", "contact_submit": "Enviar Mensaje", "contact_success_h": "Mensaje Recibido", "contact_success_p": "Gracias por contactarme. Estaré en contacto pronto.", "contact_cta_eyebrow": "¿Listo para Comenzar?", "contact_cta_h1": "Reserva tu", "contact_cta_em": "experiencia", "contact_cta_body": "Las nuevas clientas siempre comienzan con una consulta. Ahí es donde comienza la magia.", "contact_cta_btn": "Solicitar una Cita", "text_me": "Escríbeme", "hc_eyebrow": "Educación", "hc_h1": "Guía de", "hc_em": "Cuidado del Cabello", "hc_hero_body": "Tu cabello merece cuidado entre citas. Esta guía cubre todo, desde rutinas diarias hasta el cuidado posterior, para que tus resultados duren más y tu cabello se mantenga saludable.", "hc_nav_wash": "Lavado", "hc_nav_prod": "Productos", "hc_nav_after": "Cuidado Posterior", "hc_nav_prep": "Preparación", "hc_marquee": ["Lavado", "Productos", "Cuidado Posterior", "Extensiones", "Color", "Blow-out", "Preparación para la Cita"], "hc_wash_eyebrow": "Rutina Diaria", "hc_wash_h2": "¿Con qué frecuencia", "hc_wash_em": "lavarte el cabello?", "hc_wash_body": "No hay una respuesta universal. La frecuencia depende de tu tipo de cabello, cuero cabelludo y estilo de vida. Lavar demasiado elimina los aceites naturales; lavar poco acumula residuos.", "hc_prod_eyebrow": "Qué Usar", "hc_prod_h2": "Elegir los", "hc_prod_em": "Productos Correctos", "hc_prod_body": "Los productos adecuados marcan una gran diferencia en cómo se ve y siente tu cabello entre citas.", "hc_after_eyebrow": "Después de tu Cita", "hc_after_h2": "Cuidado Posterior", "hc_after_em": "por Servicio", "hc_after_body": "Cómo tratas tu cabello en las 48 a 72 horas después de tu cita importa. Sigue estas pautas para proteger tus resultados.", "hc_prep_eyebrow": "Antes de Venir", "hc_prep_h2": "Cómo Prepararte para", "hc_prep_em": "tu Cita", "hc_prep_body": "Venir preparada ayuda a aprovechar al máximo tu tiempo en el sillón y garantiza los mejores resultados posibles.", "hc_cta_eyebrow": "¿Lista para Venir?", "hc_cta_h2": "Construyamos un plan", "hc_cta_em": "para tu cabello", "hc_cta_body": "Las nuevas clientas comienzan con una consulta. Las clientas actuales pueden reservar directamente.", "hc_cta_btn": "Solicitar una Consulta", "gl_eyebrow": "El Trabajo", "gl_h1": "Galería de", "gl_em": "Clientas", "gl_hero_body": "Un vistazo a resultados reales de clientas reales. Cada transformación es única, intencional y construida alrededor de la persona.", "gl_marquee": ["Color", "Extensiones", "Balayage", "Cortes", "Blow-out", "Transformaciones", "Raleigh, NC"], "gl_cta_eyebrow": "¿Lista para tu Transformación?", "gl_cta_h2": "Creemos algo", "gl_cta_em": "hermoso", "gl_cta_body": "Las nuevas clientas comienzan con una consulta. Las clientas actuales pueden reservar directamente.", "gl_cta_btn1": "Solicitar una Consulta", "gl_cta_btn2": "Reservar una Cita", "hc_wash_fine_label": "Cabello Fino o Graso", "hc_wash_fine_title": "Cada 1 a 2 Días", "hc_wash_fine_body": "El cabello fino tiende a apelmazarse rápidamente con el aceite y los productos. Lavarlo con más frecuencia ayuda a mantener el volumen y el cuero cabelludo limpio.", "hc_wash_med_label": "Cabello Normal o Medio", "hc_wash_med_title": "Cada 2 a 3 Días", "hc_wash_med_body": "El cabello normal puede aguantar más tiempo entre lavados. Un buen champú seco en el día dos o tres puede prolongar la frescura. Aplica acondicionador en las puntas, no en el cuero cabelludo.", "hc_wash_thick_label": "Cabello Grueso, Rizado o Seco", "hc_wash_thick_title": "Cada 3 a 7 Días", "hc_wash_thick_body": "Los cabellos más gruesos y rizados retienen mejor la humedad y pueden pasar más tiempo sin lavarse. Lavar con frecuencia puede causar resequedad. Enfócate en el acondicionamiento profundo.", "hc_wash_tip": "Consejo:", "hc_wash_tip_body": "Si tu cuero cabelludo tiene picazón o descamación, puede ser acumulación. Prueba un champú clarificante una vez al mes para reiniciar tu cuero cabelludo.", "hc_prod_intro": "Los productos adecuados marcan una gran diferencia en cómo se ve y siente tu cabello entre citas. Aquí lo que buscar según tu tipo de cabello y servicio.", "hc_prod_color_label": "Cabello con Color", "hc_prod_color_title": "Sin Sulfatos, Apto para Color", "hc_prod_color_body": "El color se desvanece más rápido con sulfatos agresivos. Usa un champú sin sulfatos formulado para cabello con color.", "hc_prod_color_l1": "Busca: apto para color, sin sulfatos, protección UV", "hc_prod_color_l2": "Evita: champús clarificantes (úsalos con moderación), agua caliente", "hc_prod_color_l3": "Agrega: acondicionador con matiz semanal para rubias", "hc_prod_ext_label": "Extensiones", "hc_prod_ext_title": "Ligero y Sin Residuos", "hc_prod_ext_body": "La acumulación de productos en los lazos puede causar deslizamiento y daño. Mantén limpio y ligero cerca de las raíces.", "hc_prod_ext_l1": "Busca: sin sulfatos, apto para extensiones, hidratante", "hc_prod_ext_l2": "Evita: aceites o sueros cerca de los lazos", "hc_prod_ext_l3": "Agrega: spray desenredante para el cepillado diario", "hc_prod_dry_label": "Cabello Seco o Dañado", "hc_prod_dry_title": "Balance de Humedad y Proteína", "hc_prod_dry_body": "El cabello seco necesita hidratación, pero demasiada proteína puede volverlo quebradizo. Alterna entre tratamientos hidratantes y de proteína.", "hc_prod_dry_l1": "Busca: aceite de argán, keratina, manteca de karité, ácido hialurónico", "hc_prod_dry_l2": "Evita: productos con alcohol, calor excesivo sin protección", "hc_prod_dry_l3": "Agrega: mascarilla de acondicionamiento profundo semanal", "hc_prod_tip": "Regla general:", "hc_prod_tip_body": "Menos es más. Demasiados productos pueden causar acumulación que apelmaza el cabello y opaca el color. Comienza con champú, acondicionador y un producto de peinado.", "hc_after_intro": "Cómo tratas tu cabello en las 48 a 72 horas después de tu cita importa. Sigue estas pautas para proteger tus resultados.", "hc_color_label": "Después de un Servicio de Color", "hc_color_title": "Protege y Preserva", "hc_color_s1_h": "Espera 48 a 72 horas antes de lavarlo", "hc_color_s1_b": "El cabello recién teñido necesita tiempo para que la cutícula se cierre y el pigmento se fije. Lavarlo demasiado pronto causa decoloración prematura.", "hc_color_s2_h": "Usa agua fría o tibia", "hc_color_s2_b": "El agua caliente abre la cutícula del cabello y acelera la pérdida de color. El agua fría sella la cutícula y preserva la vibración.", "hc_color_s3_h": "Cambia a un champú apto para color", "hc_color_s3_b": "Usa una fórmula sin sulfatos y apta para color desde el primer lavado después del servicio.", "hc_color_s4_h": "Evita el cloro y el agua salada", "hc_color_s4_b": "Ambos eliminan el color rápidamente. Si nadas, usa gorra o enjuaga el cabello con agua limpia inmediatamente después.", "hc_blowout_label": "Después de un Blow-out", "hc_blowout_title": "Prolonga la Duración de tu Estilo", "hc_blowout_s1_h": "Evita la humedad por 24 horas", "hc_blowout_s1_b": "El vapor, el sudor y la humedad son los enemigos del blow-out. Trata de mantenerte seca al menos el primer día.", "hc_blowout_s2_h": "Duerme en una funda de seda", "hc_blowout_s2_b": "La seda reduce la fricción y ayuda a mantener la forma del peinado durante la noche. Una trenza suelta también ayuda.", "hc_blowout_s3_h": "Usa champú seco estratégicamente", "hc_blowout_s3_b": "Aplica champú seco en las raíces el día dos o tres para refrescar el volumen sin lavar. Déjalo actuar unos minutos antes de cepillar.", "hc_blowout_s4_h": "Retoca con calor bajo", "hc_blowout_s4_b": "El segundo día, un cepillo redondo con secador de baja temperatura o plancha en baja puede revivir el estilo sin daño.", "hc_ext_label": "Después de Extensiones", "hc_ext_title": "Cuida tu Inversión", "hc_ext_s1_h": "Cepilla suavemente dos veces al día", "hc_ext_s1_b": "Usa un cepillo de cerdas suaves desde las puntas hacia arriba. Nunca cepilles desde la raíz hacia abajo ya que esto ejerce tensión en los lazos.", "hc_ext_s2_h": "Lava con cuidado", "hc_ext_s2_b": "Lava en movimiento descendente, nunca circular. El lavado circular puede enredar las extensiones y debilitar los lazos.", "hc_ext_s3_h": "Seca completamente antes de dormir", "hc_ext_s3_b": "Dormir con extensiones mojadas puede causar enredos y debilitar el pegado. Siempre sécalas completamente antes de acostarte.", "hc_ext_s4_h": "Trenza suavemente por la noche", "hc_ext_s4_b": "Una trenza o coleta suave previene los enredos mientras duermes y reduce el estrés en los lazos.", "hc_cut_label": "Después de un Corte", "hc_cut_title": "Mantén tu Forma Fresca", "hc_cut_s1_h": "Programa tu próximo recorte", "hc_cut_s1_b": "La mayoría de los cortes se benefician de un recorte cada 6 a 12 semanas. Los recortes regulares evitan que las puntas abiertas se propaguen.", "hc_cut_s2_h": "Usa los productos de peinado correctos", "hc_cut_s2_b": "Adapta los productos a tu textura. El cabello fino necesita fijación ligera; el cabello grueso se beneficia de cremas alisadoras.", "hc_cut_s3_h": "Protege del calor", "hc_cut_s3_b": "Siempre aplica protector de calor antes de usar herramientas calientes. Esto previene la rotura y mantiene las puntas saludables.", "hc_cut_s4_h": "Recorta las puntas abiertas de inmediato", "hc_cut_s4_b": "Las puntas abiertas se propagan si no se tratan. Incluso un pequeño recorte cada pocas semanas mantiene el estilo limpio.", "hc_prep_intro": "Venir preparada ayuda a aprovechar al máximo tu tiempo en el sillón y garantiza los mejores resultados posibles.", "hc_prep_color_label": "Para un Servicio de Color", "hc_prep_color_title": "Llega con el Cabello Limpio y Seco", "hc_prep_color_body": "Lava tu cabello 24 a 48 horas antes de tu cita de color. El cabello ligeramente sucio es ideal ya que los aceites naturales protegen el cuero cabelludo durante el proceso.", "hc_prep_color_l1": "Evita productos o aceites pesados el día de la cita", "hc_prep_color_l2": "Trae fotos de referencia de los colores que te gustan", "hc_prep_color_l3": "Usa una camiseta que no te importe manchar", "hc_prep_color_l4": "Esté lista para hablar honestamente sobre tu historial de cabello", "hc_prep_ext_label": "Para Extensiones", "hc_prep_ext_title": "Limpio y Sin Productos", "hc_prep_ext_body": "Las extensiones se adhieren y mezclan mejor cuando el cabello está recién lavado y libre de residuos de productos.", "hc_prep_ext_l1": "Lava el cabello la mañana o noche anterior", "hc_prep_ext_l2": "No apliques aceites, sueros ni champú seco", "hc_prep_ext_l3": "Llega con el cabello suelto y desenredado", "hc_prep_ext_l4": "Trae fotos de tus metas de largo y volumen", "hc_prep_cut_label": "Para un Corte o Blow-out", "hc_prep_cut_title": "Llega Cómoda", "hc_prep_cut_body": "Para un corte, llega con el cabello en su estado natural para que el corte pueda adaptarse a cómo se comporta tu cabello. Para un blow-out, llega con el cabello limpio.", "hc_prep_cut_l1": "Evita productos pesados la mañana de la cita", "hc_prep_cut_l2": "Trae fotos de estilos que te gusten", "hc_prep_cut_l3": "Dile a la estilista tu rutina diaria", "hc_prep_cut_l4": "Sé específica sobre cuánto largo quieres mantener", "hc_prep_tip": "¿Primera vez?", "hc_prep_tip_body": "Usa el formulario de solicitud de consulta para compartir una foto de tu cabello natural antes de tu cita. Esto ayuda a Ezequiel a venir preparado con un plan para ti.", "hc_prep_tip_link": "Solicita una consulta aquí."}, "pt": {"nav_home": "Início", "nav_services": "Serviços", "nav_meet": "Conheça o Ez", "nav_contact": "Contato", "nav_haircare": "Cuidado do Cabelo", "nav_gallery": "Galeria", "nav_book": "Agendar", "index_marquee": ["Privado", "Bilíngue", "Intencional", "Raleigh, NC", "Extensões de Luxo", "Cor Personalizada", "Com Agendamento"], "index_hero_eyebrow": "Estúdio Privado · Raleigh, NC", "index_hero_h1": "Onde o Cabelo Encontra", "index_hero_em": "INTENÇÃO", "index_hero_body": "Uma experiência privada construída em torno do seu cabelo. Atendendo clientes em português, espanhol e inglês, cada agendamento é personalizado para o seu estilo de vida, sua textura e seus objetivos.", "index_hero_btn1": "Reservar uma Sessão", "index_hero_btn2": "Ver Serviços", "index_scroll": "Rolar", "index_p1_title": "Privado", "index_p1_body": "Uma experiência individual em um espaço tranquilo e focado. Sem distrações. Apenas você, seu cabelo e atenção total.", "index_p2_title": "Intencional", "index_p2_body": "Cada técnica, produto e decisão é tomada com propósito. Para resultados duradouros e um cabelo que se sente tão bem quanto parece.", "index_p3_title": "Seu", "index_p3_body": "Sem modelos, sem atalhos. Cada agendamento é moldado em torno da sua textura, seu estilo de vida e o que você realmente quer.", "index_svc_eyebrow": "O Que Ofereço", "index_svc_h1": "Serviços Personalizados,", "index_svc_em": "Criados para Você", "index_c1_label": "Serviço", "index_c1_title": "Cor Sem Esforço", "index_c1_desc": "Balayage e foilayage suave criando cor dimensional e natural, fácil de manter.", "index_c1_ap1": "Balayage e foilayage suave criando cor dimensional que cresce lindamente. Perfeito para quem quer resultados naturais sem manutenção constante.", "index_c1_ap2": "Cada consulta de cor começa com uma conversa sobre seu histórico, estilo de vida e objetivos.", "index_c1_abtn": "Agendar", "index_c2_label": "Serviço", "index_c2_title": "Cortes e Penteado", "index_c2_desc": "Personalizado para se adaptar ao seu cabelo: sua textura, sua rotina, seu estilo de vida.", "index_c2_ap1": "Cada corte é moldado em torno da sua rotina, textura, estilo. Não uma fórmula. Um corte que funciona na sua vida real.", "index_c2_ap2": "Inclui finalização com escova para que você saia se sentindo incrível.", "index_c2_abtn": "Agendar", "index_c3_label": "Serviço", "index_c3_title": "Extensões", "index_c3_desc": "Extensões personalizadas para sua textura, estilo de vida e objetivos. Comprimento, volume ou ambos. De forma completamente natural.", "index_c3_ap1": "Extensões personalizadas para sua textura, densidade, estilo de vida e objetivos. Vou explicar cada método, manutenção e preços na sua consulta, sem surpresas.", "index_c3_ap2": "Seja comprimento, volume ou ambos, o resultado parecerá e se sentirá completamente natural.", "index_c3_abtn": "Solicitar Consulta", "index_learn_more": "Ver Mais", "index_view_all": "Ver Todos os Serviços", "index_testi_eyebrow": "Opinião dos Clientes", "index_testi_h1": "O Que Meus Clientes", "index_testi_em": "Estão Dizendo", "index_t1": "Nunca me senti tão vista em um salão. Ezequiel ouviu exatamente o que eu queria e entregou o cabelo com o qual estou obcecada.", "index_t1_author": "Maria L.", "index_t2": "O ambiente privado fez toda a diferença. Foi relaxante e minha cor ficou absolutamente deslumbrante. Vale cada centavo.", "index_t2_author": "Ashley R.", "index_t3": "Poder falar em espanhol durante o agendamento tornou tudo muito confortável. Trabalho e cuidado excepcionais.", "index_t3_author": "Carmen V.", "index_about_eyebrow": "Conheça o Artista", "index_about_h1": "O cabelo é mais do que", "index_about_em": "um serviço.", "index_about_body": "Com experiência em cor, extensões e corte de precisão, trago maestria técnica e toque pessoal a cada agendamento. Atendendo em português, espanhol e inglês, meu estúdio foi construído com a crença de que o luxo deve ser acessível, intencional e exclusivamente seu.", "index_about_btn": "Minha História", "index_cta_eyebrow": "Pronto Quando Você Estiver", "index_cta_h1": "Pronto para criar algo", "index_cta_em": "bonito?", "index_cta_body": "Nova no EzHairr? Comece com uma consulta para revisar seu histórico e construir um plano juntos.", "index_cta_btn1": "Agendar uma Consulta", "index_cta_btn2": "Nova Clienta? Solicitar Consulta", "footer_navigate": "Navegar", "footer_contact": "Entre em Contato", "footer_copy": "© 2026 EzHairr. Todos os direitos reservados.", "footer_location": "Raleigh, Carolina do Norte", "svc_marquee": ["Cor", "Extensões", "Cortes", "Penteado", "Balayage", "Foilayage", "Escova", "Consultas"], "svc_eyebrow": "O Que Ofereço", "svc_h1": "Menu de", "svc_em": "Serviços", "svc_body": "Cada serviço é uma conversa. Novas clientes são sempre bem-vindas para começar com uma consulta.", "svc_first_title": "Primeira vez?", "svc_first_sub": "Comece com uma Consulta", "svc_first_body": "Não sabe qual serviço é certo para você? Uma consulta é sempre o melhor primeiro passo. Vou revisar seu histórico e construir um plano que se adapte à sua vida.", "svc_first_btn": "Solicitar uma Consulta", "svc1_em": "Corte de Cabelo", "svc1_body": "Cada corte é personalizado para se adaptar ao seu cabelo. Sua rotina, seu estilo, sua textura — um corte que funciona na vida real.", "svc2_h1": "Cor", "svc2_em": "Sem Esforço", "svc2_body": "Balayage e foilayage suave criando cor dimensional e natural, fácil de manter.", "svc3_h1": "Cor", "svc3_em": "Clássica", "svc3_body": "De retoques de raiz e cor sólida a gloss e transformações completas. Adaptado ao seu cabelo e objetivos.", "svc4_h1": "Serviços de", "svc4_em": "Extensões", "svc4_body": "Durante sua consulta, vou explicar tudo sobre extensões: método, manutenção e preços, sem surpresas.", "svc5_h1": "Escova", "svc5_em": "Clássica", "svc5_body": "Um acabamento polido e suave que dura. Adaptado ao seu tipo de cabelo, liso, volumoso ou algo intermediário.", "svc_book": "Agendar", "svc_cta_eyebrow": "Pronto para Começar?", "svc_cta_h1": "Reserve sua", "svc_cta_em": "experiência", "svc_cta_body": "Novas clientes sempre começam com uma consulta. É onde a magia começa.", "svc_cta_btn": "Solicitar uma Consulta", "about_marquee": ["Privado", "Bilíngue", "Intencional", "Raleigh, NC", "Estúdio de Luxo", "Com Agendamento"], "about_eyebrow": "O Artista", "about_h1": "Conheça", "about_em": "Ezequiel", "about_hero_body": "O cabelo é mais do que um serviço. É uma relação construída sobre confiança, visão e intenção.", "about_bg_eyebrow": "História", "about_bg_h2": "Arte. ", "about_bg_em": "Conexão.", "about_bg_h2b": " Cor.", "about_p1": "Fundei o EzHairr com uma ideia simples mas poderosa: que a experiência do salão deve parecer tão boa quanto os resultados. Como estilista bilíngue em Raleigh, construí um estúdio privado onde cada cliente se sente genuinamente vista, ouvida e cuidada.", "about_p2": "Cada agendamento é construído ao redor de você. Sua textura, seu estilo de vida, sua visão. É a única maneira que conheço de trabalhar.", "about_p3": "Seja para uma transformação completa de cor ou um simples corte, você vai sair se sentindo confiante, ouvida e genuinamente cuidada.", "about_v1_title": "Atendimento Bilíngue", "about_v1_body": "Fluente em inglês e espanhol, servindo a comunidade de Raleigh com calor e facilidade.", "about_v2_title": "Estúdio Privado", "about_v2_body": "Um ambiente focado, individual. Sem multidões, sem distrações, apenas o seu agendamento.", "about_v3_title": "Resultados Intencionais", "about_v3_body": "Cada decisão é tomada com propósito, dos produtos usados ao estilo final.", "about_cta_eyebrow": "Pronto para Começar?", "about_cta_h1": "Reserve sua", "about_cta_em": "experiência", "about_cta_body": "Novas clientes sempre começam com uma consulta. É onde a magia começa.", "about_cta_btn": "Solicitar uma Consulta", "contact_marquee": ["Agendar", "Dizer Olá", "Raleigh, NC", "(919) 444-2266", "hello@ezhairr.com", "Com Agendamento"], "contact_eyebrow": "Entre em Contato", "contact_h1": "Vamos", "contact_em": "Conversar", "contact_hero_body": "Tem uma pergunta? Quer agendar? Encontre as informações de contato de Ezequiel abaixo. Novas clientes podem usar o formulário para solicitar uma consulta.", "contact_info_eyebrow": "Info do Estúdio", "contact_info_h2": "Encontre-me", "contact_info_em": "", "contact_loc": "Localização", "contact_phone": "Telefone / Mensagem", "contact_email_lbl": "E-mail", "contact_hours": "Horário", "contact_hours_v1": "Somente com agendamento.", "contact_hours_v2": "Novas clientes começam com uma consulta.", "contact_lang": "Idiomas", "contact_lang_v": "Inglês e Espanhol", "contact_book_btn": "Agendar uma Consulta", "contact_form_eyebrow": "Novos Clientes", "contact_form_h2": "Solicitar uma", "contact_form_em": "Consulta", "contact_form_note": "Nova no EzHairr? Todas as novas clientes começam com uma consulta. Preencha o formulário e inclua uma foto do seu cabelo natural. Ezequiel entrará em contato em 24 horas.", "contact_existing": "Já é cliente?", "contact_existing_link": "Agende seu horário diretamente aqui.", "contact_fname": "Nome", "contact_lname": "Sobrenome", "contact_email": "Endereço de E-mail", "contact_phone_opt": "Telefone (opcional)", "contact_service": "Serviço de Interesse", "contact_service_default": "Selecione um serviço", "contact_msg": "Mensagem", "contact_photo": "Foto do Seu Cabelo Natural (opcional)", "contact_photo_hint": "Novos clientes são encorajados a compartilhar uma foto do seu cabelo natural para que Ezequiel possa se preparar.", "contact_submit": "Enviar Mensagem", "contact_success_h": "Mensagem Recebida", "contact_success_p": "Obrigado por entrar em contato. Estarei em contato em breve.", "contact_cta_eyebrow": "Pronto para Começar?", "contact_cta_h1": "Reserve sua", "contact_cta_em": "experiência", "contact_cta_body": "Novas clientes sempre começam com uma consulta. É onde a magia começa.", "contact_cta_btn": "Solicitar uma Consulta", "text_me": "Me Mande uma Mensagem", "hc_eyebrow": "Educação", "hc_h1": "Guia de", "hc_em": "Cuidado do Cabelo", "hc_hero_body": "Seu cabelo merece cuidado entre os agendamentos. Este guia cobre tudo, desde rotinas diárias até cuidados pós-serviço, para que seus resultados durem mais.", "hc_nav_wash": "Lavagem", "hc_nav_prod": "Produtos", "hc_nav_after": "Cuidados Pós", "hc_nav_prep": "Preparação", "hc_marquee": ["Lavagem", "Produtos", "Cuidados Pós", "Extensões", "Cor", "Escova", "Preparação para o Agendamento"], "hc_wash_eyebrow": "Rotina Diária", "hc_wash_h2": "Com que frequência", "hc_wash_em": "lavar o cabelo?", "hc_wash_body": "Não há uma resposta universal. A frequência depende do seu tipo de cabelo, couro cabeludo e estilo de vida. Lavar demais remove os óleos naturais; lavar de menos acumula resíduos.", "hc_prod_eyebrow": "O Que Usar", "hc_prod_h2": "Escolhendo os", "hc_prod_em": "Produtos Certos", "hc_prod_body": "Os produtos certos fazem uma diferença significativa em como seu cabelo fica e se sente entre os agendamentos.", "hc_after_eyebrow": "Após o Agendamento", "hc_after_h2": "Cuidados Pós", "hc_after_em": "por Serviço", "hc_after_body": "Como você trata o cabelo nas 48 a 72 horas após o agendamento importa. Siga estas orientações para proteger seus resultados.", "hc_prep_eyebrow": "Antes de Vir", "hc_prep_h2": "Como se Preparar para", "hc_prep_em": "o Agendamento", "hc_prep_body": "Vir preparada ajuda a aproveitar ao máximo o tempo na cadeira e garante os melhores resultados possíveis.", "hc_cta_eyebrow": "Pronta para Vir?", "hc_cta_h2": "Vamos criar um plano", "hc_cta_em": "para o seu cabelo", "hc_cta_body": "Novas clientes começam com uma consulta. Clientes atuais podem agendar diretamente.", "hc_cta_btn": "Solicitar uma Consulta", "gl_eyebrow": "O Trabalho", "gl_h1": "Galeria de", "gl_em": "Clientes", "gl_hero_body": "Um olhar sobre resultados reais de clientes reais. Cada transformação é única, intencional e construída ao redor do indivíduo.", "gl_marquee": ["Cor", "Extensões", "Balayage", "Cortes", "Escova", "Transformações", "Raleigh, NC"], "gl_cta_eyebrow": "Pronta para sua Transformação?", "gl_cta_h2": "Vamos criar algo", "gl_cta_em": "bonito", "gl_cta_body": "Novas clientes começam com uma consulta. Clientes atuais podem agendar diretamente.", "gl_cta_btn1": "Solicitar uma Consulta", "gl_cta_btn2": "Agendar uma Consulta", "hc_wash_fine_label": "Cabelo Fino ou Oleoso", "hc_wash_fine_title": "A Cada 1 a 2 Dias", "hc_wash_fine_body": "O cabelo fino tende a ficar pesado rapidamente com óleo e produtos. Lavar com mais frequência ajuda a manter o volume e o couro cabeludo limpo.", "hc_wash_med_label": "Cabelo Normal ou Médio", "hc_wash_med_title": "A Cada 2 a 3 Dias", "hc_wash_med_body": "O cabelo normal aguenta mais tempo entre lavagens. Um bom dry shampoo no segundo ou terceiro dia pode prolongar a frescura. Aplique condicionador nos comprimentos e pontas.", "hc_wash_thick_label": "Cabelo Grosso, Cacheado ou Seco", "hc_wash_thick_title": "A Cada 3 a 7 Dias", "hc_wash_thick_body": "Cabelos mais grossos e cacheados retêm melhor a umidade. Lavar com frequência pode causar ressecamento. Foque no condicionamento profundo e em selar a umidade com óleo ou creme.", "hc_wash_tip": "Dica:", "hc_wash_tip_body": "Se o seu couro cabeludo está com coceira ou descamação, pode ser acúmulo de produto. Tente um shampoo clarificante uma vez por mês para resetar.", "hc_prod_intro": "Os produtos certos fazem uma diferença significativa entre agendamentos. Aqui está o que procurar com base no seu tipo de cabelo e serviço.", "hc_prod_color_label": "Cabelo com Coloração", "hc_prod_color_title": "Sem Sulfato, Apto para Cor", "hc_prod_color_body": "A cor desbota mais rápido com sulfatos agressivos. Use um shampoo sem sulfato formulado para cabelo colorido.", "hc_prod_color_l1": "Procure: apto para cor, sem sulfato, proteção UV", "hc_prod_color_l2": "Evite: shampoos clarificantes (use com moderação), água quente", "hc_prod_color_l3": "Adicione: condicionador matizador semanal para loiras", "hc_prod_ext_label": "Extensões", "hc_prod_ext_title": "Leve e Sem Resíduos", "hc_prod_ext_body": "Acúmulo de produto nos pontos de fixação pode causar deslizamento e danos. Mantenha limpo e leve perto das raízes.", "hc_prod_ext_l1": "Procure: sem sulfato, próprio para extensões, hidratante", "hc_prod_ext_l2": "Evite: óleos ou séruns perto dos pontos de fixação", "hc_prod_ext_l3": "Adicione: spray desembaraçador para escovação diária", "hc_prod_dry_label": "Cabelo Seco ou Danificado", "hc_prod_dry_title": "Equilíbrio de Umidade e Proteína", "hc_prod_dry_body": "O cabelo seco precisa de hidratação, mas muita proteína pode deixá-lo quebradiço. Alterne entre tratamentos hidratantes e de proteína.", "hc_prod_dry_l1": "Procure: óleo de argan, queratina, manteiga de karité, ácido hialurônico", "hc_prod_dry_l2": "Evite: produtos com álcool, calor excessivo sem proteção", "hc_prod_dry_l3": "Adicione: máscara de condicionamento profundo semanal", "hc_prod_tip": "Regra geral:", "hc_prod_tip_body": "Menos é mais. Muitos produtos em camadas podem causar acúmulo que pesa o cabelo e opaca a cor. Comece com shampoo, condicionador e um produto de finalização.", "hc_after_intro": "Como você trata o cabelo nas 48 a 72 horas após o agendamento importa. Siga estas orientações para proteger seus resultados.", "hc_color_label": "Após um Serviço de Cor", "hc_color_title": "Proteja e Preserve", "hc_color_s1_h": "Espere 48 a 72 horas antes de lavar", "hc_color_s1_b": "O cabelo recém colorido precisa de tempo para a cutícula fechar e o pigmento fixar. Lavar cedo demais causa desbotamento prematuro.", "hc_color_s2_h": "Use água fria ou morna", "hc_color_s2_b": "A água quente abre a cutícula e acelera a perda de cor. A água fria sela a cutícula e preserva a vivacidade.", "hc_color_s3_h": "Troque para um shampoo apto para cor", "hc_color_s3_b": "Use uma fórmula sem sulfato e apta para cor desde a primeira lavagem após o serviço.", "hc_color_s4_h": "Evite cloro e água salgada", "hc_color_s4_b": "Ambos removem a cor rapidamente. Se nadar, use touca ou enxágue o cabelo com água limpa imediatamente.", "hc_blowout_label": "Após uma Escova", "hc_blowout_title": "Prolongue a Duração do Estilo", "hc_blowout_s1_h": "Evite umidade por 24 horas", "hc_blowout_s1_b": "Vapor, suor e umidade são os inimigos de uma escova fresca. Tente ficar seca pelo menos no primeiro dia.", "hc_blowout_s2_h": "Durma em fronha de seda", "hc_blowout_s2_b": "A seda reduz o atrito e ajuda o estilo a manter a forma durante a noite. Uma trança solta também ajuda.", "hc_blowout_s3_h": "Use dry shampoo estrategicamente", "hc_blowout_s3_b": "Aplique dry shampoo nas raízes no segundo ou terceiro dia para refrescar o volume sem lavar. Deixe agir alguns minutos antes de escovar.", "hc_blowout_s4_h": "Retoque com calor baixo", "hc_blowout_s4_b": "No segundo dia, uma escova redonda com secador em temperatura baixa pode reviver o estilo sem danos.", "hc_ext_label": "Após Extensões", "hc_ext_title": "Cuide do Seu Investimento", "hc_ext_s1_h": "Escove suavemente duas vezes ao dia", "hc_ext_s1_b": "Use uma escova de cerdas macias das pontas para cima. Nunca escove da raiz para baixo pois isso coloca tensão nos pontos de fixação.", "hc_ext_s2_h": "Lave com cuidado", "hc_ext_s2_b": "Lave em movimento descendente, nunca circular. Lavar em circular pode enredar as extensões e enfraquecer os pontos de fixação.", "hc_ext_s3_h": "Seque completamente antes de dormir", "hc_ext_s3_b": "Dormir com extensões molhadas pode causar emaranhamento e enfraquecer a fixação. Sempre seque completamente antes de deitar.", "hc_ext_s4_h": "Trance suavemente à noite", "hc_ext_s4_b": "Uma trança ou rabo de cavalo suave previne emaranhamentos enquanto você dorme e reduz o estresse nos pontos de fixação.", "hc_cut_label": "Após um Corte", "hc_cut_title": "Mantenha o Formato Fresco", "hc_cut_s1_h": "Agende o próximo aparado", "hc_cut_s1_b": "A maioria dos cortes se beneficia de um aparado a cada 6 a 12 semanas. Aparados regulares evitam que as pontas se abram.", "hc_cut_s2_h": "Use os produtos de finalização certos", "hc_cut_s2_b": "Adapte os produtos à sua textura. Cabelo fino precisa de fixação leve; cabelo grosso se beneficia de cremes alisadores.", "hc_cut_s3_h": "Proteja do calor", "hc_cut_s3_b": "Sempre aplique protetor térmico antes de usar ferramentas de calor. Isso previne a quebra e mantém as pontas saudáveis.", "hc_cut_s4_h": "Apare as pontas abertas rapidamente", "hc_cut_s4_b": "Pontas abertas se propagam se não forem tratadas. Mesmo um pequeno aparado a cada poucas semanas mantém o estilo limpo.", "hc_prep_intro": "Vir preparada ajuda a aproveitar ao máximo o tempo na cadeira e garante os melhores resultados possíveis.", "hc_prep_color_label": "Para um Serviço de Cor", "hc_prep_color_title": "Venha com Cabelo Limpo e Seco", "hc_prep_color_body": "Lave o cabelo 24 a 48 horas antes da consulta de cor. Cabelo levemente sujo é ideal pois os óleos naturais protegem o couro cabeludo durante o processo.", "hc_prep_color_l1": "Evite produtos ou óleos pesados no dia da consulta", "hc_prep_color_l2": "Traga fotos de referência das cores que você gosta", "hc_prep_color_l3": "Vista uma roupa que não se importe de manchar", "hc_prep_color_l4": "Esteja pronta para falar honestamente sobre seu histórico de cabelo", "hc_prep_ext_label": "Para Extensões", "hc_prep_ext_title": "Limpo e Sem Produtos", "hc_prep_ext_body": "As extensões aderem e se misturam melhor quando o cabelo está recém lavado e completamente livre de resíduos.", "hc_prep_ext_l1": "Lave o cabelo na manhã ou noite anterior", "hc_prep_ext_l2": "Não aplique óleos, séruns ou dry shampoo", "hc_prep_ext_l3": "Venha com o cabelo solto e desembaraçado", "hc_prep_ext_l4": "Traga fotos dos seus objetivos de comprimento e volume", "hc_prep_cut_label": "Para um Corte ou Escova", "hc_prep_cut_title": "Venha Confortável", "hc_prep_cut_body": "Para um corte, venha com o cabelo no estado natural para que o corte possa ser adaptado ao comportamento real do seu cabelo. Para escova, venha com o cabelo limpo.", "hc_prep_cut_l1": "Evite produtos pesados na manhã da consulta", "hc_prep_cut_l2": "Traga fotos de estilos que você gosta", "hc_prep_cut_l3": "Informe ao estilista sua rotina diária", "hc_prep_cut_l4": "Seja específica sobre quanto comprimento quer manter", "hc_prep_tip": "Primeira vez?", "hc_prep_tip_body": "Use o formulário de solicitação de consulta para compartilhar uma foto do seu cabelo natural antes do agendamento. Isso ajuda Ezequiel a vir preparado com um plano para você.", "hc_prep_tip_link": "Solicite uma consulta aqui."}};
